-- Additive AI Virtual Staff module. No existing object is altered or removed.
CREATE TABLE `ai_agents` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`name` VARCHAR(160) NOT NULL,`slug` VARCHAR(160) NOT NULL,`avatar` VARCHAR(500) NULL,`role` VARCHAR(160) NOT NULL,`department` VARCHAR(160) NOT NULL,`description` TEXT NULL,`instructions` LONGTEXT NULL,`systemPrompt` LONGTEXT NULL,`status` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE',`modelProvider` VARCHAR(80) NOT NULL DEFAULT 'openai-compatible',`modelName` VARCHAR(120) NOT NULL DEFAULT 'default',`temperature` DOUBLE NOT NULL DEFAULT 0.2,`maxTokens` INTEGER NOT NULL DEFAULT 4096,`language` VARCHAR(16) NOT NULL DEFAULT 'en',`version` INTEGER NOT NULL DEFAULT 1,`isPublished` BOOLEAN NOT NULL DEFAULT true,`isDefault` BOOLEAN NOT NULL DEFAULT false,`createdBy` INTEGER NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,UNIQUE INDEX `ai_agents_ispId_slug_key`(`ispId`,`slug`),INDEX `ai_agents_ispId_status_idx`(`ispId`,`status`),INDEX `ai_agents_createdAt_idx`(`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_permissions` (`id` INTEGER NOT NULL AUTO_INCREMENT,`agentId` INTEGER NOT NULL,`module` VARCHAR(120) NOT NULL,`resource` VARCHAR(160) NULL,`canRead` BOOLEAN NOT NULL DEFAULT true,`canCreate` BOOLEAN NOT NULL DEFAULT false,`canUpdate` BOOLEAN NOT NULL DEFAULT false,`canDelete` BOOLEAN NOT NULL DEFAULT false,`canExecute` BOOLEAN NOT NULL DEFAULT false,`requiresApproval` BOOLEAN NOT NULL DEFAULT false,INDEX `ai_agent_permissions_agentId_idx`(`agentId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_tools` (`id` INTEGER NOT NULL AUTO_INCREMENT,`agentId` INTEGER NOT NULL,`toolKey` VARCHAR(120) NOT NULL,`toolName` VARCHAR(160) NOT NULL,`description` TEXT NULL,`configuration` JSON NULL,`enabled` BOOLEAN NOT NULL DEFAULT true,`requiresApproval` BOOLEAN NOT NULL DEFAULT false,`riskLevel` VARCHAR(24) NOT NULL DEFAULT 'LOW',UNIQUE INDEX `ai_agent_tools_agentId_toolKey_key`(`agentId`,`toolKey`),INDEX `ai_agent_tools_agentId_idx`(`agentId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_knowledge_sources` (`id` INTEGER NOT NULL AUTO_INCREMENT,`agentId` INTEGER NOT NULL,`sourceType` VARCHAR(80) NOT NULL,`sourceId` VARCHAR(191) NULL,`title` VARCHAR(191) NOT NULL,`description` TEXT NULL,`enabled` BOOLEAN NOT NULL DEFAULT true,INDEX `ai_agent_knowledge_sources_agentId_idx`(`agentId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_conversations` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`userId` INTEGER NOT NULL,`title` VARCHAR(191) NOT NULL,`status` VARCHAR(32) NOT NULL DEFAULT 'ACTIVE',`summary` TEXT NULL,`pinned` BOOLEAN NOT NULL DEFAULT false,`archived` BOOLEAN NOT NULL DEFAULT false,`lastMessageAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,INDEX `ai_agent_conversations_ispId_userId_idx`(`ispId`,`userId`),INDEX `ai_agent_conversations_agentId_idx`(`agentId`),INDEX `ai_agent_conversations_lastMessageAt_idx`(`lastMessageAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_messages` (`id` INTEGER NOT NULL AUTO_INCREMENT,`conversationId` INTEGER NOT NULL,`senderType` VARCHAR(32) NOT NULL,`senderId` INTEGER NULL,`role` VARCHAR(32) NOT NULL,`content` LONGTEXT NOT NULL,`structuredData` JSON NULL,`toolCalls` JSON NULL,`attachments` JSON NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_messages_conversationId_createdAt_idx`(`conversationId`,`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_tasks` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`requestedBy` INTEGER NOT NULL,`title` VARCHAR(191) NOT NULL,`description` TEXT NULL,`taskType` VARCHAR(80) NOT NULL,`priority` VARCHAR(24) NOT NULL DEFAULT 'MEDIUM',`status` VARCHAR(32) NOT NULL DEFAULT 'PENDING',`input` JSON NULL,`output` JSON NULL,`error` TEXT NULL,`startedAt` DATETIME(3) NULL,`completedAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),`updatedAt` DATETIME(3) NOT NULL,INDEX `ai_agent_tasks_ispId_status_idx`(`ispId`,`status`),INDEX `ai_agent_tasks_agentId_status_idx`(`agentId`,`status`),INDEX `ai_agent_tasks_createdAt_idx`(`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_actions` (`id` INTEGER NOT NULL AUTO_INCREMENT,`taskId` INTEGER NULL,`agentId` INTEGER NOT NULL,`actionType` VARCHAR(120) NOT NULL,`targetModule` VARCHAR(120) NOT NULL,`targetResource` VARCHAR(160) NULL,`targetId` VARCHAR(191) NULL,`input` JSON NULL,`output` JSON NULL,`riskLevel` VARCHAR(24) NOT NULL DEFAULT 'LOW',`approvalRequired` BOOLEAN NOT NULL DEFAULT false,`approvalStatus` VARCHAR(32) NOT NULL DEFAULT 'NOT_REQUIRED',`executedAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_actions_taskId_idx`(`taskId`),INDEX `ai_agent_actions_agentId_createdAt_idx`(`agentId`,`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_approvals` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`taskId` INTEGER NULL,`actionId` INTEGER NULL,`requestedBy` INTEGER NOT NULL,`assignedTo` INTEGER NULL,`approvalType` VARCHAR(80) NOT NULL,`status` VARCHAR(32) NOT NULL DEFAULT 'PENDING',`reason` TEXT NULL,`approvedAt` DATETIME(3) NULL,`rejectedAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_approvals_ispId_status_idx`(`ispId`,`status`),INDEX `ai_agent_approvals_agentId_status_idx`(`agentId`,`status`),INDEX `ai_agent_approvals_createdAt_idx`(`createdAt`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_activity_logs` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`userId` INTEGER NULL,`eventType` VARCHAR(100) NOT NULL,`description` TEXT NOT NULL,`metadata` JSON NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_activity_logs_ispId_createdAt_idx`(`ispId`,`createdAt`),INDEX `ai_agent_activity_logs_agentId_createdAt_idx`(`agentId`,`createdAt`),INDEX `ai_agent_activity_logs_userId_idx`(`userId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_usage` (`id` INTEGER NOT NULL AUTO_INCREMENT,`ispId` INTEGER NOT NULL,`agentId` INTEGER NOT NULL,`userId` INTEGER NOT NULL,`modelProvider` VARCHAR(80) NOT NULL,`modelName` VARCHAR(120) NOT NULL,`inputTokens` INTEGER NOT NULL DEFAULT 0,`outputTokens` INTEGER NOT NULL DEFAULT 0,`totalTokens` INTEGER NOT NULL DEFAULT 0,`estimatedCost` DOUBLE NOT NULL DEFAULT 0,`durationMs` INTEGER NOT NULL DEFAULT 0,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),INDEX `ai_agent_usage_ispId_createdAt_idx`(`ispId`,`createdAt`),INDEX `ai_agent_usage_agentId_createdAt_idx`(`agentId`,`createdAt`),INDEX `ai_agent_usage_userId_idx`(`userId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `ai_agent_versions` (`id` INTEGER NOT NULL AUTO_INCREMENT,`agentId` INTEGER NOT NULL,`version` INTEGER NOT NULL,`instructions` LONGTEXT NULL,`systemPrompt` LONGTEXT NULL,`tools` JSON NULL,`permissions` JSON NULL,`publishedBy` INTEGER NULL,`publishedAt` DATETIME(3) NULL,`createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),UNIQUE INDEX `ai_agent_versions_agentId_version_key`(`agentId`,`version`),INDEX `ai_agent_versions_agentId_idx`(`agentId`),PRIMARY KEY (`id`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
